/****** Metadato ******/
INSERT [ManV2].[Metadato] ([metClave], [metDescrip], [metDescripIng]) VALUES (	10	, N'"Si se hace bien, la agricultura, la silvicultura y las piscifactorías pueden suministrarnos comida nutritiva para todos y generar ingresos decentes, mientras se apoya el desarrollo de las gentes del campo y la protección del medio ambiente. Pero ahora mismo, nuestros suelos, agua, océanos, bosques y nuestra biodiversidad están siendo rápidamente degradados. El cambio climático está poniendo mayor presión sobre los recursos de los que dependemos y aumentan los riesgos asociados a desastres tales como sequías e inundaciones. Muchas campesinas y campesinos ya no pueden ganarse la vida en sus tierras, lo que les obliga a emigrar a las ciudades en busca de oportunidades. Necesitamos una profunda reforma del sistema mundial de agricultura y alimentación si queremos nutrir a los 925 millones de hambrientos que existen actualmente y los dos mil millones adicionales de personas que vivirán en el ańo 2050. El sector alimentario y el sector agrícola ofrecen soluciones claves para el desarrollo y son vitales para la eliminación del hambre y la pobreza."  Fuente: http://www.un.org/sustainabledevelopment/es/hunger/ (consultado el 3 de junio de 2016).', N'"It is time to rethink how we grow, share and consume our food. If done right, agriculture, forestry and fisheries can provide nutritious food for all and generate decent incomes, while supporting people-centred rural development and protecting the environment. Right now, our soils, freshwater, oceans, forests and biodiversity are being rapidly degraded. Climate change is putting even more pressure on the resources we depend on, increasing risks associated with disasters such as droughts and floods. Many rural women and men can no longer make ends meet on their land, forcing them to migrate to cities in search of opportunities. A profound change of the global food and agriculture system is needed if we are to nourish today’s 795 million hungry and the additional 2 billion people expected by 2050. The food and agriculture sector offers key solutions for development, and is central for hunger and poverty eradication."  Source: http://www.un.org/sustainabledevelopment/hunger/ (consulted on June 3, 2016).')

/****** Descripcion ******/

--INSERT [ManV2].[Descripcion] ([desClave], [desDescrip], [desAbrevia], [desCodigo], [desDescripIng], [desAbreviaIng], [desCodigoIng]) VALUES (	258	,N'Población total',N'',N'',N'Total population',N'',N'')
INSERT [ManV2].[Descripcion] ([desClave], [desDescrip], [desAbrevia], [desCodigo], [desDescripIng], [desAbreviaIng], [desCodigoIng]) VALUES (	452	,N'De aquí a 2030, poner fin al hambre y asegurar el acceso de todas las personas, en particular los pobres y las personas en situaciones de vulnerabilidad, incluidos los nińos menores de 1 ańo, a una alimentación sana, nutritiva y suficiente durante todo el ańo',N'',N'Meta 2.1',N'By 2030, end hunger and ensure access by all people, in particular the poor and people in vulnerable situations, including infants, to safe, nutritious and sufficient food all year round',N'',N'Target 2.1')
INSERT [ManV2].[Descripcion] ([desClave], [desDescrip], [desAbrevia], [desCodigo], [desDescripIng], [desAbreviaIng], [desCodigoIng]) VALUES (	1241	,N'Proporción de la población con inseguridad alimentaria moderada o severa (carencia por acceso a la alimentación), desglosada por sexo y edad',N'',N'2.1.2',N'Proportion of the population with moderate or severe food insecurity (lack of access to food), disaggregated by sex and age',N'',N'2.1.2')
