INSERT [ManV2].[Fuentes] ([fueClave], [fueDescrip], [fueDescripIng]) VALUES (	370	,N'Consejo Nacional de Evaluación de la Política de Desarrollo Social (CONEVAL). <a target="_blank" class="liga3" href="http://www.coneval.org.mx/Informes/Coordinacion/Publicaciones%20oficiales/MEDICION_MULTIDIMENSIONAL_SEGUNDA_EDICION.pdf"> Metodología para la medición multidimensional de la pobreza en México.</a> Fecha de consulta: 05 de agosto de 2019.',N'Consejo Nacional de Evaluación de la Política de Desarrollo Social (CONEVAL). <a target="_blank" class="liga3" href="http://www.coneval.org.mx/Informes/Coordinacion/Publicaciones%20oficiales/MEDICION_MULTIDIMENSIONAL_SEGUNDA_EDICION.pdf"> Metodología para la medición multidimensional de la pobreza en México.</a> Date of consultation: August 05, 2019.')
INSERT [ManV2].[Fuentes] ([fueClave], [fueDescrip], [fueDescripIng]) VALUES (	487	,N'Instituto Nacional de Estadística y Geografía (INEGI). Módulo de Condiciones Socioeconómicas de la Encuesta Nacional de Ingresos y Gastos de los Hogares (MCS-ENIGH) 2008-2014. <a target="_blank" class="liga3" href="https://www.inegi.org.mx/programas/mcs/2008/">https://www.inegi.org.mx/programas/mcs/2008/</a>y Modelo Estadístico para la Continuidad (MEC) del MCS-ENIGH 2016 y 2018. <a target="_blank" class="liga3" href="https://www.inegi.org.mx/investigacion/eash/2018/">https://www.inegi.org.mx/investigacion/eash/2018/</a>',N'Instituto Nacional de Estadística y Geografía (INEGI). Módulo de Condiciones Socioeconómicas de la Encuesta Nacional de Ingresos y Gastos de los Hogares (MCS-ENIGH) 2008-2014. <a target="_blank" class="liga3" href="https://www.inegi.org.mx/programas/mcs/2008/">https://www.inegi.org.mx/programas/mcs/2008/</a>and Modelo Estadístico para la Continuidad (MEC) del MCS-ENIGH 2016 y 2018. <a target="_blank" class="liga3" href="https://www.inegi.org.mx/investigacion/eash/2018/">https://www.inegi.org.mx/investigacion/eash/2018/</a>')

