/****** RefInter ******/
INSERT [ManV2].[RefInter] ([riClave], [riDescrip], [riDescripIng]) VALUES (132, N'Se emplea una escala de seguridad alimentaria basada en una propuesta de Pérez-Escamilla, Melgar-Quińonez, Nord, Álvarez y Segall-Correa. Esta escala reconoce cuatro posibles niveles de inseguridad alimentaria: inseguridad alimentaria severa, inseguridad alimentaria moderada, inseguridad alimentaria leve y seguridad alimentaria.¬¬Para mayor detalle consultar:¬La <a target="_blank" class="liga3" href="http://www.coneval.gob.mx/Informes/Coordinacion/Publicaciones%20oficiales/MEDICION_MULTIDIMENSIONAL_SEGUNDA_EDICION.pdf">Metodología para la medición multidimensional de la pobreza en México.</a>',N'A food safety scale is used based on a proposal by Pérez-Escamilla, Melgar-Quińonez, Nord, Álvarez y Segall-Correa. This scale recognizes four possible levels of food insecurity: severe food insecurity, moderate food insecurity, mild food insecurity and food security.¬¬For further details consult the <a target="_blank" class="liga3" href="http://www.coneval.gob.mx/Informes/Coordinacion/Publicaciones%20oficiales/MEDICION_MULTIDIMENSIONAL_SEGUNDA_EDICION.pdf">Methodology for the multidimensional measurement of poverty in Mexico</a>')
INSERT [ManV2].[RefInter] ([riClave], [riDescrip], [riDescripIng]) VALUES (133, N'Datos de CONEVAL sobre acceso a la alimentación: <a target="_blank" class="liga3" href="http://www.coneval.gob.mx/Medicion/Paginas/PobrezaInicio.aspx">http://www.coneval.gob.mx/Medicion/Paginas/PobrezaInicio.aspx</a>',N'CONEVAL data on access to food: <a target="_blank" class="liga3" href="http://www.coneval.gob.mx/Medicion/Paginas/PobrezaInicio.aspx">http://www.coneval.gob.mx/Medicion/Paginas/PobrezaInicio.aspx</a>')

